328→    // ===== 音频解码：支持所有格式(WAV/MP3/M4A/FLAC/AMR/OGG...) =====
329→    private float[] decodeAudio(String filepath) throws Exception {
330→        MediaExtractor extractor = new MediaExtractor();
331→        extractor.setDataSource(filepath);
332→
333→        // 查找音频轨道
334→        int trackIndex = -1;
335→        MediaFormat format = null;
336→        for (int i = 0; i < extractor.getTrackCount(); i++) {
337→            MediaFormat f = extractor.getTrackFormat(i);
338→            String mime = f.getString(MediaFormat.KEY_MIME);
339→            if (mime != null && mime.startsWith("audio/")) {
340→                trackIndex = i;
341→                format = f;
342→                break;
343→            }
344→        }
345→        if (trackIndex < 0) {
346→            throw new Exception("未找到音频轨道，文件可能不是音频格式");
347→        }
348→
349→        extractor.selectTrack(trackIndex);
350→        String mime = format.getString(MediaFormat.KEY_MIME);
351→        int sampleRate = format.getInteger(MediaFormat.KEY_SAMPLE_RATE);
352→        int channels = format.getInteger(MediaFormat.KEY_CHANNEL_COUNT);
353→        Log.i(TAG, "音频格式: " + mime + ", " + sampleRate + "Hz, " + channels + "ch");
354→
355→        ByteArrayOutputStream pcmOut = new ByteArrayOutputStream();
356→
357→        if ("audio/raw".equals(mime)) {
358→            // PCM WAV: 直接从extractor读取，不需要codec解码
359→            ByteBuffer buf = ByteBuffer.allocate(65536);
360→            while (extractor.readSampleData(buf, 0) >= 0) {
361→                int pos = buf.position();
362→                byte[] chunk = new byte[pos];
363→                buf.flip();
364→                buf.get(chunk);
365→                pcmOut.write(chunk);
366→                buf.clear();
367→                extractor.advance();
368→            }
369→        } else {
370→            // 压缩格式(MP3/AAC/FLAC/AMR等): 用MediaCodec解码
371→            MediaCodec codec = MediaCodec.createDecoderByType(mime);
372→            codec.configure(format, null, null, 0);
373→            codec.start();
374→
375→            MediaCodec.BufferInfo info = new MediaCodec.BufferInfo();
376→            boolean inputDone = false;
377→            boolean outputDone = false;
378→
379→            while (!outputDone) {
380→                // 送入压缩数据
381→                if (!inputDone) {
382→                    int inputIdx = codec.dequeueInputBuffer(10000);
383→                    if (inputIdx >= 0) {
384→                        ByteBuffer inputBuf = codec.getInputBuffer(inputIdx);
385→                        int size = extractor.readSampleData(inputBuf, 0);
386→                        if (size < 0) {
387→                            codec.queueInputBuffer(inputIdx, 0, 0, 0,
388→                                MediaCodec.BUFFER_FLAG_END_OF_STREAM);
389→                            inputDone = true;
390→                        } else {
391→                            codec.queueInputBuffer(inputIdx, 0, size,
392→                                extractor.getSampleTime(), 0);
393→                            extractor.advance();
394→                        }
395→                    }
396→                }
397→
398→                // 取出PCM数据
399→                int outputIdx = codec.dequeueOutputBuffer(info, 10000);
400→                if (outputIdx >= 0) {
401→                    if ((info.flags & MediaCodec.BUFFER_FLAG_END_OF_STREAM) != 0) {
402→                        outputDone = true;
403→                    }
404→                    if (info.size > 0) {
405→                        ByteBuffer outputBuf = codec.getOutputBuffer(outputIdx);
406→                        byte[] chunk = new byte[info.size];
407→                        outputBuf.get(chunk);
408→                        pcmOut.write(chunk);
409→                    }
410→                    codec.releaseOutputBuffer(outputIdx, false);
411→                } else if (outputIdx == MediaCodec.INFO_OUTPUT_FORMAT_CHANGED) {
412→                    MediaFormat outFmt = codec.getOutputFormat();
413→                    sampleRate = outFmt.getInteger(MediaFormat.KEY_SAMPLE_RATE);
414→                    channels = outFmt.getInteger(MediaFormat.KEY_CHANNEL_COUNT);
415→                    Log.i(TAG, "解码输出格式: " + sampleRate + "Hz, " + channels + "ch");
416→                }
417→            }
418→
419→            codec.stop();
420→            codec.release();
421→        }
422→
423→        extractor.release();
424→
425→        byte[] pcmBytes = pcmOut.toByteArray();
426→        if (pcmBytes.length < 100) {
427→            throw new Exception("音频解码后数据为空 (原格式: " + mime + ")");
428→        }
429→
430→        // PCM bytes -> float samples (16-bit little-endian)
431→        int numSamples = pcmBytes.length / 2;
432→        float[] allSamples = new float[numSamples];
433→        ByteBuffer bb = ByteBuffer.wrap(pcmBytes).order(ByteOrder.LITTLE_ENDIAN);
434→        for (int i = 0; i < numSamples; i++) {
435→            allSamples[i] = bb.getShort() / 32768.0f;
436→        }
437→
438→        // 立体声 -> 单声道
439→        float[] mono;
440→        if (channels > 1) {
441→            int monoLen = numSamples / channels;
442→            mono = new float[monoLen];
443→            for (int i = 0; i < monoLen; i++) {
444→                float sum = 0;
445→                for (int c = 0; c < channels; c++) {
446→                    sum += allSamples[i * channels + c];
447→                }
448→                mono[i] = sum / channels;
449→            }
450→        } else {
451→            mono = allSamples;
452→        }
453→
454→        // 重采样到16kHz
455→        if (sampleRate != 16000) {
456→            Log.i(TAG, "重采样: " + sampleRate + "Hz -> 16000Hz");
457→            mono = resample(mono, sampleRate, 16000);
458→        }
459→
460→        float durationSec = mono.length / 16000.0f;
461→        Log.i(TAG, "解码完成: " + mono.length + " samples, " +
462→            String.format("%.1f", durationSec) + "s @ 16kHz mono");
463→
464→        if (durationSec < 0.3f) {
465→            throw new Exception("音频太短 (" + String.format("%.1f", durationSec) + "秒)，无法识别");
466→        }
467→
468→        return mono;
469→    }
