471→    // ===== 线性插值重采样 =====
472→    private float[] resample(float[] input, int fromRate, int toRate) {
473→        double ratio = (double) fromRate / toRate;
474→        int outputLen = (int) (input.length / ratio);
475→        float[] output = new float[outputLen];
476→        for (int i = 0; i < outputLen; i++) {
477→            double srcIdx = i * ratio;
478→            int idx = (int) srcIdx;
479→            double frac = srcIdx - idx;
480→            if (idx + 1 < input.length) {
481→                output[i] = (float) (input[idx] * (1 - frac) + input[idx + 1] * frac);
482→            } else if (idx < input.length) {
483→                output[i] = input[idx];
484→            }
485→        }
486→        return output;
487→    }
