489→    // ===== Sherpa-ONNX 离线识别（分段提升准确率） =====
490→    private String transcribeSherpa(String audioFile) throws Exception {
491→        // 解码音频为16kHz单声道（支持WAV/MP3/M4A/FLAC/AMR/OGG等）
492→        float[] samples = decodeAudio(audioFile);
493→
494→        AssetManager assetManager = getAssets();
495→
496→        OfflineParaformerModelConfig paraformerConfig = new OfflineParaformerModelConfig();
497→        paraformerConfig.setModel("models/paraformer/model.int8.onnx");
498→
499→        OfflineModelConfig modelConfig = new OfflineModelConfig();
500→        modelConfig.setParaformer(paraformerConfig);
501→        modelConfig.setTokens("models/paraformer/tokens.txt");
502→        modelConfig.setNumThreads(4);
503→        modelConfig.setDebug(false);
504→
505→        OfflineRecognizerConfig config = new OfflineRecognizerConfig();
506→        config.setModelConfig(modelConfig);
507→        config.setDecodingMethod("greedy_search");
508→
509→        OfflineRecognizer recognizer = new OfflineRecognizer(assetManager, config);
510→
511→        // 分段识别：每段30秒，提高长音频准确率
512→        int chunkSamples = 30 * 16000;
513→        int totalChunks = (int) Math.ceil((double) samples.length / chunkSamples);
514→        StringBuilder allText = new StringBuilder();
515→
516→        if (totalChunks <= 1) {
517→            // 短音频直接识别
518→            OfflineStream stream = recognizer.createStream();
519→            stream.acceptWaveform(samples, 16000);
520→            recognizer.decode(stream);
521→            OfflineRecognizerResult result = recognizer.getResult(stream);
522→            allText.append(result.getText() != null ? result.getText().trim() : "");
523→            stream.release();
524→        } else {
525→            // 长音频分段识别
526→            for (int ci = 0; ci < totalChunks; ci++) {
527→                int finalCi = ci;
528→                runOnUiThread(() -> tvStatus.setText(
529→                    String.format("离线识别 %d/%d...", finalCi + 1, totalChunks)));
530→
531→                int start = ci * chunkSamples;
532→                // 加1秒重叠避免截断
533→                int overlap = ci > 0 ? 16000 : 0;
534→                int actualStart = Math.max(0, start - overlap);
535→                int end = Math.min(samples.length, start + chunkSamples);
536→                int len = end - actualStart;
537→
538→                if (len < 1600) continue; // 不足0.1秒跳过
539→
540→                float[] chunk = new float[len];
541→                System.arraycopy(samples, actualStart, chunk, 0, len);
542→
543→                OfflineStream stream = recognizer.createStream();
544→                stream.acceptWaveform(chunk, 16000);
545→                recognizer.decode(stream);
546→                OfflineRecognizerResult result = recognizer.getResult(stream);
547→                String text = result.getText() != null ? result.getText().trim() : "";
548→
549→                if (!text.isEmpty()) {
550→                    // 去除重叠部分导致的重复（最长公共后缀/前缀匹配，窗口30字）
551→                    if (ci > 0 && allText.length() > 0 && overlap > 0) {
552→                        String prev = allText.toString();
553→                        int maxCheck = Math.min(30, Math.min(prev.length(), text.length()));
554→                        int bestMatch = 0;
